	s.AddTool(
		mcplib.NewTool("wiki_set-content-state",
			mcplib.WithDescription("Sets the content state of the content specified and creates a new version (publishes the content without changing the body) of the content with the new state. You may pass in either an id of a state, or the name and color of a desired new state. If all 3 are passed in, id will be used. If the name and color passed in already exist under the current user's existing custom states, the existing state will be reused. If custom states are disabled in the space of the content (which can be determined by getting the content state space settings of the content's space) then this set will fail. You may not remove a content state via this PUT request. You must use the DELETE method. A specified state is required in the body of this request. **[Permissions](https://confluence.atlassian.com/x/_AozKw) required**: Permission to edit the content. Required: id, status. Optional: color, id-2, name. Returns the updated ContentStateResponse."),
			mcplib.WithString("id", mcplib.Required(), mcplib.Description("The Id of the content whose content state is to be set.")),
			mcplib.WithString("status", mcplib.Required(), mcplib.Description("Status of content onto which state will be placed. If draft, then draft state will change.")),
			mcplib.WithString("color", mcplib.Description("Color of state. Must be in 6 digit hex form (#FFFFFF).")),
			mcplib.WithNumber("id-2", mcplib.Description("id of state. This can be 0,1, or 2 if you wish to specify a default space state.")),
			mcplib.WithString("name", mcplib.Description("Name of content state. Maximum 20 characters.")),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("PUT", "/wiki/rest/api/content/{id}/state", false, false, nil, []mcpParamBinding{{PublicName: "id", WireName: "id", Location: "path"}, {PublicName: "status", WireName: "status", Location: "query"}, {PublicName: "color", WireName: "color", Location: "body"}, {PublicName: "id-2", WireName: "id", Location: "body"}, {PublicName: "name", WireName: "name", Location: "body"}}, []string{"id"}),
	)
